1	---
2	import '../styles/global.css';
3	import { config } from '../data/hub.config';
4	import Breadcrumbs from '../components/Breadcrumbs.astro';
5	
6	interface Props {
7	  title: string;
8	  description?: string;
9	  image?: string;
10	}
11	
12	const {
13	  title,
14	  description = config.tagline,
15	  image = '/og-default.svg'
16	} = Astro.props;
17	
18	const canonicalURL = new URL(Astro.url.pathname, Astro.site || config.domains.hub);
19	
20	// --- Active page detection ---
21	const currentPath = Astro.url.pathname;
22	const isWaterSection = currentPath.startsWith('/water');
23	const isHome = currentPath === '/';
24	
25	function navClass(href: string): string {
26	  let active = href === '/'
27	    ? currentPath === '/'
28	    : currentPath === href || currentPath === href.replace(/\/$/, '') || currentPath.startsWith(href);
29	  // Physical pillar routes to /water/, Financial pillar routes to /business/
30	  if (href === '/water/' && currentPath.startsWith('/pillars/physical')) active = true;
31	  if (href === '/business/' && currentPath.startsWith('/pillars/financial')) active = true;
32	  return active
33	    ? 'text-white'
34	    : 'text-ocean-400 hover:text-white';
35	}
36	
37	function mobileNavClass(href: string): string {
38	  const active = href === '/'
39	    ? currentPath === '/'
40	    : currentPath === href || currentPath === href.replace(/\/$/, '') || currentPath.startsWith(href);
41	  return active
42	    ? 'text-white border-l-2 border-ocean-400 pl-3'
43	    : 'text-ocean-400 active:text-white';
44	}
45	
46	function subNavClass(href: string): string {
47	  const normalized = currentPath.replace(/\/$/, '');
48	  const hrefNormalized = href.replace(/\/$/, '');
49	  return normalized === hrefNormalized
50	    ? 'text-white'
51	    : 'text-ocean-400/60 hover:text-white/70';
52	}
53	
54	// --- Breadcrumb data ---
55	type BreadcrumbItem = { label: string; href?: string };
56	const breadcrumbs: BreadcrumbItem[] = [];
57	
58	if (!isHome) {
59	  breadcrumbs.push({ label: 'Home', href: '/' });
60	
61	  if (isWaterSection) {
62	    const subPath = currentPath.replace('/water/', '').replace(/\/$/, '');
63	    if (!subPath || subPath === 'water') {
64	      breadcrumbs.push({ label: 'Water' });
65	    } else if (subPath === 'quiz') {
66	      breadcrumbs.push({ label: 'Water', href: '/water/' });
67	      breadcrumbs.push({ label: 'Quiz' });
68	    } else if (subPath === 'explore') {
69	      breadcrumbs.push({ label: 'Water', href: '/water/' });
70	      breadcrumbs.push({ label: 'Branches' });
71	    } else {
72	      const branchName = config.branches.find(b => b.slug === subPath)?.name;
73	      breadcrumbs.push({ label: 'Water', href: '/water/' });
74	      breadcrumbs.push({ label: branchName || subPath });
75	    }
76	  } else if (currentPath.startsWith('/pillars/')) {
77	    const slug = currentPath.replace('/pillars/', '').replace(/\/$/, '');
78	    const pillar = config.pillars.find(p => p.slug === slug);
79	    breadcrumbs.push({ label: pillar?.name || slug });
80	  } else if (currentPath.startsWith('/business')) {
81	    breadcrumbs.push({ label: 'Business' });
82	  } else if (currentPath.startsWith('/research')) {
83	    breadcrumbs.push({ label: 'Research' });
84	  }
85	}
86	---
87	
88	<!doctype html>
89	<html lang="en">
90	  <head>
91	    <meta charset="UTF-8" />
92	    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
93	    <title>{title}</title>
94	    
95	    <!-- Primary Meta Tags -->
96	    <meta name="title" content={title} />
97	    <meta name="description" content={description} />
98	    <link rel="canonical" href={canonicalURL} />
99	
100	    <!-- Open Graph / Facebook -->
101	    <meta property="og:type" content="website" />
102	    <meta property="og:url" content={canonicalURL} />
103	    <meta property="og:title" content={title} />
104	    <meta property="og:description" content={description} />
105	    <meta property="og:image" content={new URL(image, Astro.site)} />
106	
107	    <!-- Twitter -->
108	    <meta name="twitter:card" content="summary_large_image" />
109	    <meta name="twitter:url" content={canonicalURL} />
110	    <meta name="twitter:title" content={title} />
111	    <meta name="twitter:description" content={description} />
112	    <meta name="twitter:image" content={new URL(image, Astro.site)} />
113	
114	    <link rel="preconnect" href="https://fonts.googleapis.com" />
115	    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
116	    <link
117	      href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;1,400&family=Inter:wght@300;400;500&display=swap"
118	      rel="stylesheet"
119	    />
120	  </head>
121	  <body class="min-h-screen flex flex-col bg-ocean-900 text-white/60">
122	    <nav aria-label="Main" class="fixed top-0 left-0 right-0 z-50 bg-ocean-900/60 backdrop-blur-xl border-b border-white/[0.04]">
123	      <!-- Primary nav row -->
124	      <div class="max-w-6xl mx-auto px-6 md:px-10 py-4 flex items-center justify-between">
125	        <a href="/" class="font-heading text-base font-light text-white/70 hover:text-white transition-colors tracking-wide">
126	          {config.name}
127	        </a>
128	        <!-- Desktop nav -->
129	        <div class="hidden md:flex gap-7">
130	          <a href="/water/" class:list={['text-[11px] font-medium tracking-[0.15em] uppercase transition-colors', navClass('/water/')]}>Water</a>
131	          <a href="/pillars/inner" class:list={['text-[11px] font-medium tracking-[0.15em] uppercase transition-colors', navClass('/pillars/inner')]}>Inner</a>
132	          <a href="/pillars/identity" class:list={['text-[11px] font-medium tracking-[0.15em] uppercase transition-colors', navClass('/pillars/identity')]}>Identity</a>
133	          <a href="/business/" class:list={['text-[11px] font-medium tracking-[0.15em] uppercase transition-colors', navClass('/business/')]}>Business</a>
134	          <a href="/research" class:list={['text-[11px] font-medium tracking-[0.15em] uppercase transition-colors', navClass('/research')]}>Research</a>
135	        </div>
136	        <!-- Mobile hamburger -->
137	        <button id="nav-toggle" class="md:hidden p-2 -mr-2 text-ocean-400" aria-label="Menu">
138	          <svg id="nav-icon-open" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="4" y1="7" x2="20" y2="7"/><line x1="4" y1="12" x2="20" y2="12"/><line x1="4" y1="17" x2="20" y2="17"/></svg>
139	          <svg id="nav-icon-close" class="hidden" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"><line x1="6" y1="6" x2="18" y2="18"/><line x1="6" y1="18" x2="18" y2="6"/></svg>
140	        </button>
141	      </div>
142	      <!-- Water sub-nav (desktop only, Water section pages) -->
143	      {isWaterSection && (
144	        <div class="hidden md:block border-t border-white/[0.03]">
145	          <div class="max-w-6xl mx-auto px-6 md:px-10 py-2.5 flex gap-6">
146	            <a href="/water/" class:list={['text-[10px] font-medium tracking-[0.12em] uppercase transition-colors', subNavClass('/water/')]}>Water Home</a>
147	            <a href="/water/quiz" class:list={['text-[10px] font-medium tracking-[0.12em] uppercase transition-colors', subNavClass('/water/quiz')]}>Quiz</a>
148	            <a href="/water/explore" class:list={['text-[10px] font-medium tracking-[0.12em] uppercase transition-colors', subNavClass('/water/explore')]}>Branches</a>
149	          </div>
150	        </div>
151	      )}
152	      <!-- Mobile menu panel -->
153	      <div id="nav-menu" class="hidden md:hidden border-t border-white/[0.04] bg-ocean-900/95 backdrop-blur-xl">
154	        <div class="px-6 py-5 flex flex-col gap-1">
155	          <!-- Water section -->
156	          <span class="text-[9px] tracking-[0.2em] uppercase text-white/15 font-medium pt-1 pb-2">Water</span>
157	          <a href="/water/" class:list={['text-[13px] font-medium tracking-[0.12em] uppercase py-1.5 pl-4 transition-colors', mobileNavClass('/water/')]}>Water Home</a>
158	          <a href="/water/quiz" class:list={['text-[13px] font-medium tracking-[0.12em] uppercase py-1.5 pl-4 transition-colors', mobileNavClass('/water/quiz')]}>Take the Quiz</a>
159	          <a href="/water/explore" class:list={['text-[13px] font-medium tracking-[0.12em] uppercase py-1.5 pl-4 transition-colors', mobileNavClass('/water/explore')]}>Explore Branches</a>
160	          <!-- The Spiral section -->
161	          <span class="text-[9px] tracking-[0.2em] uppercase text-white/15 font-medium pt-4 pb-2">The Spiral</span>
162	          <a href="/pillars/inner" class:list={['text-[13px] font-medium tracking-[0.12em] uppercase py-1.5 pl-4 transition-colors', mobileNavClass('/pillars/inner')]}>Inner Sovereignty</a>
163	          <a href="/pillars/identity" class:list={['text-[13px] font-medium tracking-[0.12em] uppercase py-1.5 pl-4 transition-colors', mobileNavClass('/pillars/identity')]}>Identity Sovereignty</a>
164	          <a href="/business/" class:list={['text-[13px] font-medium tracking-[0.12em] uppercase py-1.5 pl-4 transition-colors', mobileNavClass('/business/')]}>Business</a>
165	          <a href="/research" class:list={['text-[13px] font-medium tracking-[0.12em] uppercase py-1.5 pl-4 transition-colors', mobileNavClass('/research')]}>Research</a>
166	        </div>
167	      </div>
168	    </nav>
169	    <script>
170	      const toggle = document.getElementById('nav-toggle');
171	      const menu = document.getElementById('nav-menu');
172	      const iconOpen = document.getElementById('nav-icon-open');
173	      const iconClose = document.getElementById('nav-icon-close');
174	      toggle?.addEventListener('click', () => {
175	        const open = menu?.classList.toggle('hidden') === false;
176	        iconOpen?.classList.toggle('hidden', open);
177	        iconClose?.classList.toggle('hidden', !open);
178	      });
179	      // Close on link tap
180	      menu?.querySelectorAll('a').forEach(a => a.addEventListener('click', () => {
181	        menu.classList.add('hidden');
182	        iconOpen?.classList.remove('hidden');
183	        iconClose?.classList.add('hidden');
184	      }));
185	    </script>
186	
187	    <main class:list={['flex-1', isWaterSection ? 'pt-[88px]' : 'pt-[56px]']}>
188	      <Breadcrumbs items={breadcrumbs} />
189	      <slot />
190	    </main>
191	
192	    <footer class="border-t border-white/[0.03] bg-ocean-900">
193	      <div class="max-w-6xl mx-auto px-6 md:px-10 py-16">
194	        <div class="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-10 md:gap-8">
195	          <!-- Brand -->
196	          <div>
197	            <a href="/" class="font-heading text-[15px] font-light text-white/50 hover:text-white/70 transition-colors">{config.name}</a>
198	            <p class="mt-2 text-[11px] text-white/15 tracking-[0.08em]">{config.domains.hub}</p>
199	          </div>
200	          <!-- Water -->
201	          <div>
202	            <p class="text-[10px] tracking-[0.15em] uppercase text-white/30 font-medium mb-3">Water</p>
203	            <div class="flex flex-col gap-2">
204	              <a href="/water/" class="text-[12px] text-white/20 hover:text-white/40 transition-colors">Water Home</a>
205	              <a href="/water/quiz" class="text-[12px] text-white/20 hover:text-white/40 transition-colors">Take the Quiz</a>
206	              <a href="/water/explore" class="text-[12px] text-white/20 hover:text-white/40 transition-colors">Explore Branches</a>
207	              {config.branches.map(branch => (
208	                <a href={`/water/${branch.slug}`} class="text-[12px] text-white/15 hover:text-white/30 transition-colors pl-2">{branch.name}</a>
209	              ))}
210	            </div>
211	          </div>
212	          <!-- The Spiral -->
213	          <div>
214	            <p class="text-[10px] tracking-[0.15em] uppercase text-white/30 font-medium mb-3">The Spiral</p>
215	            <div class="flex flex-col gap-2">
216	              {config.pillars.filter(p => p.slug !== 'physical' && p.slug !== 'financial').map(pillar => (
217	                <a href={pillar.url} class="text-[12px] text-white/20 hover:text-white/40 transition-colors">{pillar.name}</a>
218	              ))}
219	              <a href="/business/" class="text-[12px] text-white/20 hover:text-white/40 transition-colors">Financial Sovereignty</a>
220	            </div>
221	          </div>
222	          <!-- Learn -->
223	          <div>
224	            <p class="text-[10px] tracking-[0.15em] uppercase text-white/30 font-medium mb-3">Learn</p>
225	            <div class="flex flex-col gap-2">
226	              <a href="/research" class="text-[12px] text-white/20 hover:text-white/40 transition-colors">Research Bibliography</a>
227	            </div>
228	          </div>
229	        </div>
230	        <!-- Copyright -->
231	        <div class="mt-12 pt-6 border-t border-white/[0.03] text-center">
232	          <p class="text-[11px] text-white/15">&copy; {new Date().getFullYear()} {config.name}</p>
233	        </div>
234	      </div>
235	    </footer>
236	
237	    <script>
238	      // Citation tooltips — lazy-load data on first hover
239	      let citations = null;
240	      let tooltip = null;
241	
242	      function createTooltip() {
243	        const el = document.createElement('div');
244	        el.id = 'cite-tooltip';
245	        el.style.cssText = `
246	          position:fixed; z-index:9999; pointer-events:none; opacity:0;
247	          transition:opacity 0.15s; max-width:320px; padding:14px 16px;
248	          background:#0c2e33; border:1px solid rgba(17,154,158,0.25);
249	          border-radius:10px; box-shadow:0 12px 40px rgba(0,0,0,0.5);
250	          font-family:Inter,system-ui,sans-serif;
251	        `;
252	        document.body.appendChild(el);
253	        return el;
254	      }
255	
256	      async function loadCitations() {
257	        if (citations) return citations;
258	        try {
259	          const res = await fetch('/citations.json');
260	          citations = await res.json();
261	        } catch { citations = []; }
262	        return citations;
263	      }
264	
265	      function findCitation(id) {
266	        return citations?.find(c => c.id === id);
267	      }
268	
269	      function renderTooltip(cite, isBio) {
270	        return `
271	          <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.12em;color:#7dd3d7;margin-bottom:6px;">
272	            ${isBio ? 'Peer-Reviewed Research' : 'Sacred / Philosophical Source'}
273	          </div>
274	          <div style="font-size:13px;font-weight:500;color:#fff;line-height:1.4;margin-bottom:6px;">
275	            ${cite.source}
276	          </div>
277	          <div style="font-size:12px;color:rgba(255,255,255,0.5);line-height:1.5;font-style:italic;">
278	            "${cite.detail}"
279	          </div>
280	          ${cite.context.startsWith('http') ? `<div style="font-size:10px;color:#3dbfc4;margin-top:8px;font-family:monospace;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${cite.context}</div>` : ''}
281	        `;
282	      }
283	
284	      function positionTooltip(sup) {
285	        if (!tooltip) return;
286	        const rect = sup.getBoundingClientRect();
287	        const maxW = Math.min(320, window.innerWidth - 16);
288	        tooltip.style.maxWidth = maxW + 'px';
289	        let left = rect.left + rect.width / 2 - maxW / 2;
290	        left = Math.max(8, Math.min(left, window.innerWidth - maxW - 8));
291	        tooltip.style.left = left + 'px';
292	        tooltip.style.top = (rect.top - tooltip.offsetHeight - 8) + 'px';
293	        if (rect.top - tooltip.offsetHeight - 8 < 8) {
294	          tooltip.style.top = (rect.bottom + 8) + 'px';
295	        }
296	        tooltip.style.opacity = '1';
297	      }
298	
299	      function hideTooltip() {
300	        if (tooltip) tooltip.style.opacity = '0';
301	      }
302	
303	      let activeSup = null;
304	
305	      async function showForSup(sup) {
306	        const id = sup.textContent.trim();
307	        if (!/^[SB]-\d+$/.test(id)) return;
308	        await loadCitations();
309	        const cite = findCitation(id);
310	        if (!cite) return;
311	        if (!tooltip) tooltip = createTooltip();
312	        tooltip.innerHTML = renderTooltip(cite, id.startsWith('B-'));
313	        activeSup = sup;
314	        requestAnimationFrame(() => positionTooltip(sup));
315	      }
316	
317	      // Desktop: hover
318	      document.addEventListener('mouseover', (e) => {
319	        const sup = e.target.closest('sup');
320	        if (sup) showForSup(sup);
321	      });
322	      document.addEventListener('mouseout', (e) => {
323	        if (e.target.closest('sup')) hideTooltip();
324	      });
325	
326	      // Mobile: tap to toggle
327	      document.addEventListener('click', (e) => {
328	        const sup = e.target.closest('sup');
329	        if (sup) {
330	          e.preventDefault();
331	          if (activeSup === sup && tooltip?.style.opacity === '1') {
332	            hideTooltip();
333	            activeSup = null;
334	          } else {
335	            showForSup(sup);
336	          }
337	        } else if (tooltip?.style.opacity === '1') {
338	          hideTooltip();
339	          activeSup = null;
340	        }
341	      });
342	    </script>
343	  </body>
344	</html>
